import{_ as t,o,c as a,ag as n}from"./chunks/framework.BYYsWsaA.js";const p=JSON.parse('{"title":"Collaboration & Sharing","description":"","frontmatter":{},"headers":[],"relativePath":"guide/collaboration.md","filePath":"guide/collaboration.md"}'),r={name:"guide/collaboration.md"};function s(i,e,l,h,c,d){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="collaboration-sharing" tabindex="-1">Collaboration &amp; Sharing <a class="header-anchor" href="#collaboration-sharing" aria-label="Permalink to &quot;Collaboration &amp; Sharing&quot;">​</a></h1><p>Wafflebase lets multiple people edit the same sheet, document, or presentation at the same time. Share via link — no account required for recipients.</p><h2 id="share-a-document" tabindex="-1">Share a Document <a class="header-anchor" href="#share-a-document" aria-label="Permalink to &quot;Share a Document&quot;">​</a></h2><ol><li>Open the sheet or document you want to share</li><li>Click the <strong>Share</strong> button in the toolbar</li><li>Choose the access level: <ul><li><strong>View</strong> — Can see the content, but not edit</li><li><strong>Edit</strong> — Full editing access</li></ul></li><li>Optionally set an expiration (1 hour, 8 hours, 24 hours, or 7 days)</li><li>Click <strong>Create Link</strong> and copy the URL</li></ol><p>Send the link to anyone. They can open it in their browser without signing in.</p><h2 id="access-levels" tabindex="-1">Access Levels <a class="header-anchor" href="#access-levels" aria-label="Permalink to &quot;Access Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Permission</th><th>Viewer</th><th>Editor</th></tr></thead><tbody><tr><td>View content</td><td>Yes</td><td>Yes</td></tr><tr><td>Navigate and scroll</td><td>Yes</td><td>Yes</td></tr><tr><td>Select and copy</td><td>Yes</td><td>Yes</td></tr><tr><td>Edit content</td><td>No</td><td>Yes</td></tr><tr><td>Format (cells or text)</td><td>No</td><td>Yes</td></tr><tr><td>Undo/redo</td><td>No</td><td>Yes</td></tr></tbody></table><p>In sheets, editors can also use formulas, insert/delete rows and columns, and resize columns. In docs, editors can apply text formatting and paragraph alignment.</p><h2 id="edit-together" tabindex="-1">Edit Together <a class="header-anchor" href="#edit-together" aria-label="Permalink to &quot;Edit Together&quot;">​</a></h2><p>When a collaborator opens your shared link, you&#39;ll see:</p><ul><li><strong>Their cursor</strong> — In sheets, a colored highlight on their selected cell. In docs, a colored text cursor at their position.</li><li><strong>Their name</strong> — Appears near their cursor so you know who&#39;s editing where</li><li><strong>Live changes</strong> — Edits appear instantly with no need to refresh or save</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Each collaborator gets a unique color. If your collaborators sign in with GitHub, their name will appear next to their cursor.</p></div><h2 id="comments-mentions" tabindex="-1">Comments &amp; Mentions <a class="header-anchor" href="#comments-mentions" aria-label="Permalink to &quot;Comments &amp; Mentions&quot;">​</a></h2><p>Leave feedback without changing the content. Comments work on cells in sheets and on selected text in documents.</p><h3 id="add-a-comment" tabindex="-1">Add a comment <a class="header-anchor" href="#add-a-comment" aria-label="Permalink to &quot;Add a comment&quot;">​</a></h3><p><strong>In a sheet:</strong></p><ol><li>Select the cell you want to comment on</li><li>Right-click and choose <strong>Insert comment</strong>, or press <strong>⌘+Option+M</strong> / <strong>Ctrl+Alt+M</strong></li><li>Type your comment and click <strong>Comment</strong></li></ol><p><strong>In a document:</strong></p><ol><li>Select the text you want to comment on</li><li>Right-click and choose <strong>Insert comment</strong>, press <strong>⌘+Option+M</strong> / <strong>Ctrl+Alt+M</strong>, or click the comment icon in the toolbar</li><li>Type your comment and click <strong>Comment</strong></li></ol><p>The commented text is highlighted so everyone can see where the discussion is.</p><h3 id="reply-resolve-edit" tabindex="-1">Reply, resolve, edit <a class="header-anchor" href="#reply-resolve-edit" aria-label="Permalink to &quot;Reply, resolve, edit&quot;">​</a></h3><ul><li><strong>Reply</strong> — Open a comment and click <strong>Reply</strong> to continue the thread.</li><li><strong>Resolve</strong> — Hover the thread and click the check (✓) to resolve it. Resolved threads are tucked away but never lost.</li><li><strong>Edit / Delete</strong> — Hover your own comment and use the <strong>⋯</strong> menu. Deleting the first comment removes the whole thread.</li></ul><h3 id="the-comments-panel-documents" tabindex="-1">The comments panel (documents) <a class="header-anchor" href="#the-comments-panel-documents" aria-label="Permalink to &quot;The comments panel (documents)&quot;">​</a></h3><p>In a document, click the comment icon in the toolbar — or press <strong>⌘+Option+Shift+M</strong> / <strong>Ctrl+Alt+Shift+M</strong> — to open the comments panel. It lists every thread under <strong>Open</strong> and <strong>Resolved</strong> tabs; click a thread to jump to its text. If the text a comment was attached to is later deleted, the thread moves to an orphaned list so the conversation is preserved.</p><h3 id="mention-a-teammate" tabindex="-1">Mention a teammate <a class="header-anchor" href="#mention-a-teammate" aria-label="Permalink to &quot;Mention a teammate&quot;">​</a></h3><p>Type <strong>@</strong> inside a comment to mention a workspace member. An autocomplete list appears — keep typing to filter, then use <strong>↑ / ↓</strong> and <strong>Enter</strong> (or <strong>Tab</strong>) to pick someone. The mention is inserted as a blue chip so it stands out in the thread.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Mentions highlight who a comment is for. Only people who are members of the workspace can be mentioned.</p></div><h2 id="how-conflicts-work" tabindex="-1">How Conflicts Work <a class="header-anchor" href="#how-conflicts-work" aria-label="Permalink to &quot;How Conflicts Work&quot;">​</a></h2><p>What happens if two people edit the same cell or text at the same time?</p><p>Wafflebase uses CRDTs (Conflict-free Replicated Data Types) to handle this. Both edits are preserved in the system — the last writer&#39;s value is displayed in sheets, and concurrent text insertions are merged in docs. There&#39;s no &quot;conflict dialog&quot; or manual merge step.</p><p>In practice, presence cursors make it easy to see where others are working, so simultaneous edits to the same location are rare.</p><h2 id="manage-share-links" tabindex="-1">Manage Share Links <a class="header-anchor" href="#manage-share-links" aria-label="Permalink to &quot;Manage Share Links&quot;">​</a></h2><p>To see or revoke existing links:</p><ol><li>Open the sheet or document</li><li>Click <strong>Share</strong> in the toolbar</li><li>You&#39;ll see a list of active links with their role and expiration</li><li>Click the delete icon next to a link to revoke it immediately</li></ol><p>Revoking a link immediately blocks access — anyone with that URL will no longer be able to open it.</p><h2 id="good-to-know" tabindex="-1">Good to Know <a class="header-anchor" href="#good-to-know" aria-label="Permalink to &quot;Good to Know&quot;">​</a></h2><ul><li>Revoking or expiring a link blocks access immediately</li><li>Deleting a document automatically invalidates all its share links</li><li>Links cannot be guessed — each one is generated with a unique random ID</li><li>For sensitive data, use short expirations (1 hour or 8 hours)</li></ul><h2 id="tips-for-collaboration" tabindex="-1">Tips for Collaboration <a class="header-anchor" href="#tips-for-collaboration" aria-label="Permalink to &quot;Tips for Collaboration&quot;">​</a></h2><ul><li><strong>Use clear names</strong> — Title your sheets and documents descriptively so teammates can find them</li><li><strong>Communicate changes</strong> — If you restructure columns or reorganize content, let your team know</li><li><strong>Use separate tabs</strong> (sheets) — Give each team member their own tab for data entry, with a summary tab that pulls data using formulas</li></ul>',39)])])}const u=t(r,[["render",s]]);export{p as __pageData,u as default};
